{
  "situations": [
    {
      "dialogue": "Olha, {{NAME}}, instalei estas lâmpadas LED fortes sobre os tomateiros. Um colega me disse que a luz é o verdadeiro alimento que vai se transformar na matéria física das folhas e dos frutos. Isso está correto?",
      "imagePrompt": "A close-up of healthy tomato plants inside a modern greenhouse illuminated by bright pink and blue LED grow lights. Small water droplets are visible on the leaves.",
      "options": [
        {
          "feedback": "Exato! A luz fornece apenas a energia necessária para que o tomateiro (produtor) monte suas próprias moléculas orgânicas usando água e gás carbônico.",
          "isCorrect": true,
          "text": "A luz fornece energia para produzir matéria."
        },
        {
          "feedback": "Incorreto. A matéria física das plantas vem de moléculas como o gás carbônico do ar e a água do solo, não da luz.",
          "isCorrect": false,
          "text": "A luz é a matéria-prima dos tecidos."
        },
        {
          "feedback": "Incorreto. A água continua sendo uma matéria-prima essencial para a sobrevivência e crescimento da planta.",
          "isCorrect": false,
          "text": "A luz substitui a absorção de água."
        },
        {
          "feedback": "Incorreto. A planta usa a luz para a fotossíntese, não para digerir minerais diretamente do solo.",
          "isCorrect": false,
          "text": "A luz digere minerais diretamente."
        }
      ],
      "question": "Como você explicaria a real função da luz para essas plantas produtoras?"
    },
    {
      "dialogue": "Esta lagarta está devorando as folhas da couve sem parar. Ela está realizando um trabalho biológico imenso para conseguir crescer e se movimentar ao longo do dia.",
      "imagePrompt": "A bright green caterpillar chewing on a fresh green kale leaf. The leaf has visible bite marks. High detail, close-up.",
      "options": [
        {
          "feedback": "Perfeito! Como consumidora, a lagarta precisa ingerir matéria orgânica para obter tanto os blocos de construção (matéria) quanto a energia química armazenada.",
          "isCorrect": true,
          "text": "Ambas vêm das moléculas da folha."
        },
        {
          "feedback": "Incorreto. Animais não conseguem capturar energia luminosa do sol para realizar trabalho celular; eles dependem da energia química do alimento.",
          "isCorrect": false,
          "text": "A matéria vem da folha, a energia do sol."
        },
        {
          "feedback": "Incorreto. A matéria do corpo da lagarta vem diretamente da ingestão física da folha, e não do ar atmosférico.",
          "isCorrect": false,
          "text": "A matéria vem do ar, a energia da folha."
        },
        {
          "feedback": "Incorreto. A lagarta é uma consumidora e não consegue usar a luz solar diretamente como fonte de energia ou matéria.",
          "isCorrect": false,
          "text": "Ambas vêm diretamente da luz solar."
        }
      ],
      "question": "De onde vêm a matéria e a energia que a lagarta precisa para realizar esse trabalho?"
    },
    {
      "dialogue": "Notei que este tronco caído na floresta está ficando macio e totalmente coberto de cogumelos selvagens. Eles não têm folhas verdes e também não caçam outros animais da região.",
      "imagePrompt": "A decaying fallen tree log on a damp forest floor, with several small, pale wild mushrooms growing out of the rotting bark. Soft woodland light.",
      "options": [
        {
          "feedback": "Excelente! Fungi são decompositores. Eles secretam enzimas que digerem a matéria orgânica morta externamente para absorver os nutrientes necessários.",
          "isCorrect": true,
          "text": "Decompondo matéria orgânica morta."
        },
        {
          "feedback": "Incorreto. Cogumelos são fungos e não possuem clorofila para realizar fotossíntese, sob nenhuma condição de luz.",
          "isCorrect": false,
          "text": "Realizando fotossíntese no escuro."
        },
        {
          "feedback": "Incorreto. O calor do ar não pode ser convertido em energia de ligação química pelo metabolismo desses seres vivos.",
          "isCorrect": false,
          "text": "Absorvendo calor diretamente do ar."
        },
        {
          "feedback": "Incorreto. Cogumelos crescem e se alimentam da madeira já morta e em decomposição, e não de plantas vivas.",
          "isCorrect": false,
          "text": "Ingerindo pedaços de plantas vivas."
        }
      ],
      "question": "Como esses fungos obtêm matéria e energia para manter seu metabolismo ativo?"
    },
    {
      "dialogue": "O teste químico mostra que a água do aquário está acumulando compostos nitrogenados tóxicos liberados pelos peixes, mesmo que não haja nenhuma sobra de ração acumulada no fundo.",
      "imagePrompt": "An elegant freshwater fish tank with clear water and a couple of colorful guppies swimming near a small water filter. A scientific test tube showing a yellow-to-green chemical reaction is placed nearby.",
      "options": [
        {
          "feedback": "Correto! O metabolismo celular de proteínas e aminoácidos gera resíduos nitrogenados que os peixes precisam eliminar para manter o equilíbrio do corpo.",
          "isCorrect": true,
          "text": "Metabolismo de proteínas dos peixes."
        },
        {
          "feedback": "Incorreto. A fotossíntese consome gás carbônico e libera oxigênio, não gerando resíduos nitrogenados tóxicos.",
          "isCorrect": false,
          "text": "Fotossíntese das algas do aquário."
        },
        {
          "feedback": "Incorreto. A energia luminosa não se transforma em resíduos químicos como a amônia ou a ureia na água.",
          "isCorrect": false,
          "text": "Acúmulo de energia solar não utilizada."
        },
        {
          "feedback": "Incorreto. A evaporação da água apenas concentra as substâncias que já estavam presentes, mas a origem delas é metabólica.",
          "isCorrect": false,
          "text": "Evaporação natural da água pura."
        }
      ],
      "question": "Qual processo biológico gerou esses resíduos químicos na água?"
    }
  ]
}

